{"content":"1: package process
2: 
3: import (
4: 	"context"
5: 	"time"
6: 
7: 	"github.com/grafana/grafana/pkg/plugins"
8: )
9: 
10: const defaultKeepPluginAliveTickerDuration = time.Second
11: 
12: type Service struct {
13: 	keepPluginAliveTickerDuration time.Duration
14: }
15: 
16: func ProvideService() *Service {
17: 	return &Service{
18: 		keepPluginAliveTickerDuration: defaultKeepPluginAliveTickerDuration,
19: 	}
20: }
21: 
22: func (s *Service) Start(ctx context.Context, p *plugins.Plugin) error {
23: 	if !p.IsManaged() || !p.Backend || p.Error != nil {
24: 		return nil
25: 	}
26: 
27: 	if err := s.startPluginAndKeepItAlive(ctx, p); err != nil {
28: 		return err
29: 	}
30: 
31: 	p.Logger().Debug("Successfully started backend plugin process")
32: 	return nil
33: }
34: 
35: func (*Service) Stop(ctx context.Context, p *plugins.Plugin) error {
36: 	p.Logger().Debug("Stopping plugin process")
37: 	if err := p.Decommission(); err != nil {
38: 		return err
39: 	}
40: 
41: 	if err := p.Stop(ctx); err != nil {
42: 		return err
43: 	}
44: 
45: 	return nil
46: }
47: 
48: func (s *Service) startPluginAndKeepItAlive(ctx context.Context, p *plugins.Plugin) error {
49: 	if err := p.Start(ctx); err != nil {
50: 		return err
51: 	}
52: 
53: 	if p.IsCorePlugin() {
54: 		return nil
55: 	}
56: 
57: 	go func(p *plugins.Plugin) {
58: 		if err := s.keepPluginAlive(p); err != nil {
59: 			p.Logger().Error("Attempt to restart killed plugin process failed", "error", err)
60: 		}
61: 	}(p)
62: 
63: 	return nil
64: }
65: 
66: // keepPluginAlive will restart the plugin if the process is killed or exits
67: func (s *Service) keepPluginAlive(p *plugins.Plugin) error {
68: 	ticker := time.NewTicker(s.keepPluginAliveTickerDuration)
69: 
70: 	for {
71: 		<-ticker.C
72: 		if p.IsDecommissioned() {
73: 			p.Logger().Debug("Plugin decommissioned")
74: 			return nil
75: 		}
76: 
77: 		if !p.Exited() {
78: 			continue
79: 		}
80: 
81: 		p.Logger().Debug("Restarting plugin")
82: 		if err := p.Start(context.Background()); err != nil {
83: 			p.Logger().Error("Failed to restart plugin", "error", err)
84: 			continue
85: 		}
86: 		p.Logger().Debug("Plugin restarted")
87: 	}
88: }
