{"content":"1: package grpcplugin
2: 
3: import (
4: 	"context"
5: 	"errors"
6: 	"sync"
7: 
8: 	"github.com/grafana/grafana-plugin-sdk-go/backend"
9: 	"github.com/hashicorp/go-plugin"
10: 	"go.opentelemetry.io/otel/trace"
11: 
12: 	"github.com/grafana/grafana/pkg/infra/process"
13: 	"github.com/grafana/grafana/pkg/plugins"
14: 	"github.com/grafana/grafana/pkg/plugins/backendplugin"
15: 	"github.com/grafana/grafana/pkg/plugins/log"
16: )
17: 
18: type grpcPlugin struct {
19: 	descriptor     PluginDescriptor
20: 	clientFactory  func() *plugin.Client
21: 	client         *plugin.Client
22: 	pluginClient   *ClientV2
23: 	logger         log.Logger
24: 	mutex          sync.RWMutex
25: 	decommissioned bool
26: 	state          pluginState
27: }
28: 
29: type pluginState int
30: 
31: const (
32: 	pluginStateNotStarted pluginState = iota
33: 	pluginStateStartInit
34: 	pluginStateStartSuccess
35: 	pluginStateStartFail
36: 	pluginStateStopped
37: )
38: 
39: // newPlugin allocates and returns a new gRPC (external) backendplugin.Plugin.
40: func newPlugin(descriptor PluginDescriptor) backendplugin.PluginFactoryFunc {
41: 	return func(pluginID string, logger log.Logger, tracer trace.Tracer, env func() []string) (backendplugin.Plugin, error) {
42: 		return newGrpcPlugin(descriptor, logger, tracer, env), nil
43: 	}
44: }
45: 
46: func newGrpcPlugin(descriptor PluginDescriptor, logger log.Logger, tracer trace.Tracer, env func() []string) *grpcPlugin {
47: 	return &grpcPlugin{
48: 		descriptor: descriptor,
49: 		logger:     logger,
50: 		clientFactory: func() *plugin.Client {
51: 			return plugin.NewClient(newClientConfig(descriptor, env(), logger, tracer))
52: 		},
53: 		state: pluginStateNotStarted,
54: 	}
55: }
56: 
57: func (p *grpcPlugin) PluginID() string {
58: 	return p.descriptor.pluginID
59: }
60: 
61: func (p *grpcPlugin) Logger() log.Logger {
62: 	return p.logger
63: }
64: 
65: func (p *grpcPlugin) Start(_ context.Context) error {
66: 	p.mutex.Lock()
67: 	defer p.mutex.Unlock()
68: 
69: 	p.state = pluginStateStartInit
70: 
71: 	p.client = p.clientFactory()
72: 	rpcClient, err := p.client.Client()
73: 	if err != nil {
74: 		p.state = pluginStateStartFail
75: 		return err
76: 	}
77: 
78: 	if p.client.NegotiatedVersion() < 2 {
79: 		p.state = pluginStateStartFail
80: 		return errors.New("plugin protocol version not supported")
81: 	}
82: 	p.pluginClient, err = newClientV2(p.descriptor, p.logger, rpcClient)
83: 	if err != nil {
84: 		p.state = pluginStateStartFail
85: 		return err
86: 	}
87: 
88: 	if p.pluginClient == nil {
89: 		p.state = pluginStateStartFail
90: 		return errors.New("no compatible plugin implementation found")
91: 	}
92: 
93: 	elevated, err := process.IsRunningWithElevatedPrivileges()
94: 	if err != nil {
95: 		p.logger.Debug("Error checking plugin process execution privilege", "error", err)
96: 	}
97: 	if elevated {
98: 		p.logger.Warn("Plugin process is running with elevated privileges. This is not recommended")
99: 	}
100: 
101: 	p.state = pluginStateStartSuccess
102: 	return nil
103: }
104: 
105: func (p *grpcPlugin) Stop(_ context.Context) error {
106: 	p.mutex.Lock()
107: 	defer p.mutex.Unlock()
108: 
109: 	if p.client != nil {
110: 		p.client.Kill()
111: 	}
112: 	p.state = pluginStateStopped
113: 	return nil
114: }
115: 
116: func (p *grpcPlugin) IsManaged() bool {
117: 	return p.descriptor.managed
118: }
119: 
120: func (p *grpcPlugin) Exited() bool {
121: 	p.mutex.RLock()
122: 	defer p.mutex.RUnlock()
123: 	if p.client != nil {
124: 		return p.client.Exited()
125: 	}
126: 	return true
127: }
128: 
129: func (p *grpcPlugin) Decommission() error {
130: 	p.mutex.Lock()
131: 	defer p.mutex.Unlock()
132: 
133: 	p.decommissioned = true
134: 
135: 	return nil
136: }
137: 
138: func (p *grpcPlugin) IsDecommissioned() bool {
139: 	p.mutex.RLock()
140: 	defer p.mutex.RUnlock()
141: 	return p.decommissioned
142: }
143: 
144: func (p *grpcPlugin) Target() backendplugin.Target {
145: 	return backendplugin.TargetLocal
146: }
147: 
148: func (p *grpcPlugin) getPluginClient(ctx context.Context) (*ClientV2, bool) {
149: 	p.mutex.RLock()
150: 	defer p.mutex.RUnlock()
151: 	if p.client != nil && !p.client.Exited() && p.pluginClient != nil {
152: 		return p.pluginClient, true
153: 	}
154: 
155: 	logger := p.Logger().FromContext(ctx)
156: 	if p.state == pluginStateNotStarted {
157: 		logger.Debug("Plugin client has not been started yet")
158: 	}
159: 
160: 	if p.state == pluginStateStartInit {
161: 		logger.Debug("Plugin client is starting")
162: 	}
163: 
164: 	if p.state == pluginStateStartFail {
165: 		logger.Debug("Plugin client failed to start")
166: 	}
167: 
168: 	if p.state == pluginStateStopped {
169: 		logger.Debug("Plugin client has stopped")
170: 	}
171: 
172: 	return nil, false
173: }
174: 
175: func (p *grpcPlugin) CollectMetrics(ctx context.Context, req *backend.CollectMetricsRequest) (*backend.CollectMetricsResult, error) {
176: 	pc, ok := p.getPluginClient(ctx)
177: 	if !ok {
178: 		return nil, plugins.ErrPluginUnavailable
179: 	}
180: 	return pc.CollectMetrics(ctx, req)
181: }
182: 
183: func (p *grpcPlugin) CheckHealth(ctx context.Context, req *backend.CheckHealthRequest) (*backend.CheckHealthResult, error) {
184: 	pc, ok := p.getPluginClient(ctx)
185: 	if !ok {
186: 		return nil, plugins.ErrPluginUnavailable
187: 	}
188: 	return pc.CheckHealth(ctx, req)
189: }
190: 
191: func (p *grpcPlugin) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
192: 	pc, ok := p.getPluginClient(ctx)
193: 	if !ok {
194: 		return nil, plugins.ErrPluginUnavailable
195: 	}
196: 
197: 	return pc.QueryData(ctx, req)
198: }
199: 
200: func (p *grpcPlugin) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
201: 	pc, ok := p.getPluginClient(ctx)
202: 	if !ok {
