95: type PluginRegistration struct {
96: 	pluginRegistry registry.Service
97: 	log            log.Logger
98: }
99: 
100: // PluginRegistrationStep returns a new InitializeFunc for registering a plugin with the plugin registry.
101: func PluginRegistrationStep(pluginRegistry registry.Service) InitializeFunc {
102: 	return newPluginRegistration(pluginRegistry).Initialize
