112: // Initialize registers the plugin with the plugin registry.
113: func (r *PluginRegistration) Initialize(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
114: 	if err := r.pluginRegistry.Add(ctx, p); err != nil {
115: 		r.log.Error("Could not register plugin", "pluginId", p.ID, "error", err)
116: 		return nil, err
117: 	}
118: 	if !p.IsCorePlugin() {
119: 		r.log.Info("Plugin registered", "pluginId", p.ID)
120: 	}
121: 
122: 	return p, nil
123: }
